exercise.solution_code:
#include <iostream>
#include <string>

namespace formatter {
    inline namespace v2 {
        std::string format(const std::string& s) {
            return "[v2] " + s + " (chars: " + std::to_string(s.size()) + ")";
        }
    }
    namespace v1 {
        std::string format(const std::string& s) {
            return "[v1] " + s + " (length: " + std::to_string(s.size()) + ")";
        }
    }
}

int main() {
    std::string word;
    int version;
    std::cin >> word >> version;

    if (version == 2) {
        std::cout << formatter::format(word) << "\n";
    } else if (version == 1) {
        std::cout << formatter::v1::format(word) << "\n";
    } else {
        std::cout << "Unknown version\n";
    }

    return 0;
}
